  1→#!/usr/bin/env -S bun run --silent
  2→
  3→import { execSync } from "node:child_process";
  4→import { existsSync, mkdirSync, readFileSync, writeFileSync } from "node:fs";
  5→import { dirname, join } from "node:path";
  6→import { defineHook } from "cc-hooks-ts";
  7→import { logQuality } from "../lib/centralized-logging.ts";
  8→import "../types/tool-schemas.ts";
  9→
 10→/**
 11→ * Stop hook that runs tests/typecheck before allowing completion.
 12→ *
 13→ * Uses a file-based retry counter (.tmp/.completion-gate-retries) to
 14→ * prevent infinite loops. After MAX_RETRIES failures, switches to
 15→ * warning-only mode.
 16→ */
 17→
 18→const MAX_RETRIES = 3;
 19→const COUNTER_FILENAME = ".completion-gate-retries";
 20→
 21→function getCounterPath(): string {
 22→  const cwd = process.cwd();
 23→  return join(cwd, ".tmp", COUNTER_FILENAME);
 24→}
 25→
 26→function getRetryCount(): number {
 27→  const counterPath = getCounterPath();
 28→  try {
 29→    if (existsSync(counterPath)) {
 30→      const content = readFileSync(counterPath, "utf-8").trim();
 31→      const count = Number.parseInt(content, 10);
 32→      return Number.isNaN(count) ? 0 : count;
 33→    }
 34→  } catch {
 35→    // ignore read errors
 36→  }
 37→  return 0;
 38→}
 39→
 40→function incrementRetryCount(): number {
 41→  const counterPath = getCounterPath();
 42→  const newCount = getRetryCount() + 1;
 43→  try {
 44→    const dir = dirname(counterPath);
 45→    if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
 46→    writeFileSync(counterPath, String(newCount), "utf-8");
 47→  } catch {
 48→    // ignore write errors
 49→  }
 50→  return newCount;
 51→}
 52→
 53→function hasScript(scriptName: string): boolean {
 54→  try {
 55→    const pkg = JSON.parse(readFileSync("package.json", "utf-8"));
 56→    return Boolean(pkg.scripts?.[scriptName]);
 57→  } catch {
 58→    return false;
 59→  }
 60→}
 61→
 62→function runCheck(command: string, label: string): string | null {
 63→  try {
 64→    execSync(command, {
 65→      encoding: "utf-8",
 66→      timeout: 120000,
 67→      stdio: ["pipe", "pipe", "pipe"],
 68→    });
 69→    return null;
 70→  } catch (error: unknown) {
 71→    const err = error as { stdout?: string; stderr?: string };
 72→    const output = ((err.stdout || "") + (err.stderr || "")).trim();
 73→    const head = output.split("\n").slice(0, 20).join("\n");
 74→    return `${label} failed:\n${head}`;
 75→  }
 76→}
 77→
 78→const hook = defineHook({
 79→  trigger: { Stop: true },
 80→  run: (context) => {
 81→    try {
 82→      const { session_id } = context.input;
 83→      const retryCount = getRetryCount();
 84→
 85→      if (retryCount >= MAX_RETRIES) {
 86→        console.error(
 87→          `[completion-gate] Max retries (${MAX_RETRIES}) reached. Allowing completion with warning.`,
 88→        );
 89→        return context.success({});
 90→      }
 91→
 92→      const errors: string[] = [];
 93→
 94→      if (hasScript("typecheck")) {
 95→        const result = runCheck("pnpm typecheck", "typecheck");
 96→        if (result) {
 97→          errors.push(result);
 98→          logQuality("completion-gate", "typecheck", result, session_id);
 99→        }
100→      }
101→
102→      if (hasScript("test")) {
103→        const result = runCheck("pnpm test", "test");
104→        if (result) {
105→          errors.push(result);
106→          logQuality("completion-gate", "test", result, session_id);
107→        }
108→      }
109→
110→      if (errors.length === 0) {
111→        return context.success({});
112→      }
113→
114→      const count = incrementRetryCount();
115→      const remaining = MAX_RETRIES - count;
116→
117→      return context.json({
118→        event: "Stop",
119→        output: {
120→          decision: "block" as const,
121→          reason: `COMPLETION BLOCKED (attempt ${count}/${MAX_RETRIES}, ${remaining} remaining):\n\n${errors.join("\n\n")}\n\nFix these issues before completing.`,
122→        },
123→      });
124→    } catch (error) {
125→      console.error(`[completion-gate] Error: ${error}`);
126→      return context.success({});
127→    }
128→  },
129→});
130→
131→export default hook;
132→
133→if (import.meta.main) {
134→  const { runHook } = await import("cc-hooks-ts");
135→  await runHook(hook);
136→}
137→

